```ts
// packages/workspace/src/plugin/CatalogRegistry.ts
import type { CatalogConfig } from "../shared/plugin"

export class CatalogRegistry {
  private catalogs = new Map<string, CatalogConfig>()
  private listeners = new Set<() => void>()

  register(cfg: CatalogConfig, sourcePluginId: string): void {
    const existed = this.catalogs.has(cfg.id)
    if (existed) {
      // late-wins-on-id; warn in dev
      if (import.meta.env?.DEV) {
        console.warn(`[CatalogRegistry] catalog "${cfg.id}" registered by "${sourcePluginId}" overrides previous registration`)
      }
    }
    this.catalogs.set(cfg.id, { ...cfg, pluginId: sourcePluginId })
    this.emit()
  }

  unregister(id: string): void {
    if (this.catalogs.delete(id)) this.emit()
  }

  unregisterByPluginId(pluginId: string): void {
    let mutated = false
    for (const [id, cfg] of this.catalogs) {
      if (cfg.pluginId === pluginId) { this.catalogs.delete(id); mutated = true }
    }
    if (mutated) this.emit()
  }

  list(): readonly CatalogConfig[] { return [...this.catalogs.values()] }
  get(id: string): CatalogConfig | undefined { return this.catalogs.get(id) }

  subscribe = (cb: () => void): (() => void) => {
    this.listeners.add(cb)
    return () => this.listeners.delete(cb)
  }
  getSnapshot = (): readonly CatalogConfig[] => this.list()

  private emit(): void {
    for (const cb of [...this.listeners]) cb()
  }
}
```

