Implement the single-pass bootstrap function that takes a list of Plugin objects and fans their contributions into the per-type registries. This is the SPINE of Phase 1 — the entire plugin lifecycle.

## The full pseudocode (verbatim from v6.3 spec)

```
bootstrap(plugins, opts):
  finalSet = [
    ...defaults.filter(d => !excludeDefaults.includes(d.id)),
    ...opts.plugins
  ]

  // Pre-pass: detect duplicate Plugin.ids across the final set
  const seenPluginIds = new Set<string>()
  for (const p of finalSet) {
    if (seenPluginIds.has(p.id))
      throw new PluginError('duplicate-id', `plugin "${p.id}" registered twice`)
    seenPluginIds.add(p.id)
  }

  for each plugin in finalSet (array order):
    fan plugin.panels   → PanelRegistry        (set pluginId provenance)
    fan plugin.commands → CommandRegistry      (set pluginId provenance)
    fan plugin.catalogs → CatalogRegistry      (set pluginId provenance)
    (server) fan plugin.agentTools → AgentToolRegistry
```

That's it. Single pass. No async. No lifecycle hooks. No ordering contract beyond array order.

## Why so simple

Per v6 simplification (and codex/gemini reviewer convergence): no Phase 1 plugin needs imperative onMount, dependsOn-driven ordering, or any kind of dep graph. Defaults are prepended; host plugins follow; late-wins-on-id handles overrides via registry semantics.

## Implementation surface

```ts
// packages/workspace/src/plugin/bootstrap.ts
import type { Plugin } from "../shared/plugin"
import type { PanelRegistry } from "../registry/PanelRegistry"
import type { CommandRegistry } from "../registry/CommandRegistry"
import { PluginError } from "./PluginError"
import type { CatalogRegistry } from "./CatalogRegistry"
import type { AgentToolRegistry } from "./AgentToolRegistry"  // server-only

export interface BootstrapOpts {
  plugins: Plugin[]
  defaults: Plugin[]                          // injected by createWorkspaceAgentApp / WorkspaceProvider
  excludeDefaults?: string[]
  registries: {
    panels: PanelRegistry
    commands: CommandRegistry
    catalogs: CatalogRegistry
    agentTools?: AgentToolRegistry            // server only
  }
}

export function bootstrap(opts: BootstrapOpts): { registered: string[] } {
  const finalSet = [
    ...opts.defaults.filter(d => !(opts.excludeDefaults ?? []).includes(d.id)),
    ...opts.plugins,
  ]

  // Validate plugin-level id uniqueness
  const seen = new Set<string>()
  for (const p of finalSet) {
    if (seen.has(p.id)) throw new PluginError('duplicate-id', `plugin "${p.id}" registered twice`)
    seen.add(p.id)
  }

  for (const plugin of finalSet) {
    for (const panel of plugin.panels ?? []) opts.registries.panels.register(panel.id, { ...panel, pluginId: plugin.id })
    for (const cmd of plugin.commands ?? []) opts.registries.commands.registerCommand({ ...cmd, pluginId: plugin.id })
    for (const cat of plugin.catalogs ?? []) opts.registries.catalogs.register(cat, plugin.id)
    if (opts.registries.agentTools) {
      for (const tool of plugin.agentTools ?? []) opts.registries.agentTools.register(tool, plugin.id)
    }
  }

  return { registered: finalSet.map(p => p.id) }
}
```

