export function createVercelSandboxExec(sandbox: VercelSandbox): Sandbox {
  return {
    id: 'vercel-sandbox', placement: 'server', capabilities: ['exec'],
    async init(ctx) { /* workspace handle is also on sandbox; nothing to wire */ },
